"use strict";

function _objectSpread(a) {
    for (var b = 1; b < arguments.length; b++) {
        var c = arguments[b] == null ? {} : arguments[b];
        var d = Object.keys(c);

        if (typeof Object.getOwnPropertySymbols === "function") {
            d = d.concat(
                Object.getOwnPropertySymbols(c).filter(function (a) {
                    return Object.getOwnPropertyDescriptor(c, a).enumerable;
                })
            );
        }

        d.forEach(function (b) {
            _defineProperty(a, b, c[b]);
        });
    }
    return a;
}

function _defineProperty(a, b, c) {
    if (b in a) {
        Object.defineProperty(a, b, {
            value: c,
            enumerable: true,
            configurable: true,
            writable: true,
        });
    } else {
        a[b] = c;
    }
    return a;
}

class MetingJSElement extends HTMLElement {
    connectedCallback() {
        if (window.APlayer && window.fetch) {
            this._init();
            this._parse();
        }
    }

    disconnectedCallback() {
        if (!this.lock) {
            this.aplayer.destroy();
        }
    }

    _camelize(a) {
        return a
            .replace(/^[_.\- ]+/, "")
            .toLowerCase()
            .replace(/[_.\- ]+(\w|$)/g, (a, b) => b.toUpperCase());
    }

    _init() {
        let a = {};

        for (let b = 0; b < this.attributes.length; b += 1) {
            a[this._camelize(this.attributes[b].name)] =
                this.attributes[b].value;
        }

        let keys = [
            "server",
            "type",
            "id",
            "api",
            "auth",
            "auto",
            "lock",
            "name",
            "title",
            "artist",
            "author",
            "url",
            "cover",
            "pic",
            "lyric",
            "lrc",
        ];

        this.meta = {};

        for (let i = 0; i < keys.length; i++) {
            let key = keys[i];
            this.meta[key] = a[key];
            delete a[key];
        }

        this.config = a;

        this.api =
            this.meta.api ||
            window.meting_api ||
            "https://api.injahow.cn/meting/?server=:server&type=:type&id=:id&r=:r";

        if (this.meta.auto) {
            this._parse_link();
        }
    }

    _parse_link() {
        let rules = [
            ["music.163.com.*song.*id=(\\d+)", "netease", "song"],
            ["music.163.com.*album.*id=(\\d+)", "netease", "album"],
            ["music.163.com.*artist.*id=(\\d+)", "netease", "artist"],
            ["music.163.com.*playlist.*id=(\\d+)", "netease", "playlist"],
            ["music.163.com.*discover/toplist.*id=(\\d+)", "netease", "playlist"],
            ["y.qq.com.*song/(\\w+).html", "tencent", "song"],
            ["y.qq.com.*album/(\\w+).html", "tencent", "album"],
            ["y.qq.com.*singer/(\\w+).html", "tencent", "artist"],
            ["y.qq.com.*playsquare/(\\w+).html", "tencent", "playlist"],
            ["y.qq.com.*playlist/(\\w+).html", "tencent", "playlist"],
            ["xiami.com.*song/(\\w+)", "xiami", "song"],
            ["xiami.com.*album/(\\w+)", "xiami", "album"],
            ["xiami.com.*artist/(\\w+)", "xiami", "artist"],
            ["xiami.com.*collect/(\\w+)", "xiami", "playlist"],
        ];

        for (let i = 0; i < rules.length; i++) {
            let rule = rules[i];
            let reg = new RegExp(rule[0]);
            let match = reg.exec(this.meta.auto);

            if (match !== null) {
                this.meta.server = rule[1];
                this.meta.type = rule[2];
                this.meta.id = match[1];
                return;
            }
        }
    }

    _parse() {
        if (this.meta.url) {
            let audio = {
                name: this.meta.name || this.meta.title || "Audio name",
                artist: this.meta.artist || this.meta.author || "Audio artist",
                url: this.meta.url,
                cover: this.meta.cover || this.meta.pic,
                lrc: this.meta.lrc || this.meta.lyric || "",
                type: this.meta.type || "auto",
            };

            if (!audio.lrc) {
                this.meta.lrcType = 0;
            }

            if (this.innerText) {
                audio.lrc = this.innerText;
                this.meta.lrcType = 2;
            }

            this._loadPlayer([audio]);
            return;
        }

        let url = this.api
            .replace(":server", this.meta.server)
            .replace(":type", this.meta.type)
            .replace(":id", this.meta.id)
            .replace(":auth", this.meta.auth)
            .replace(":r", Math.random());

        fetch(url)
            .then((res) => res.json())
            .then((data) => this._loadPlayer(data));
    }

    _loadPlayer(audioList) {
        let baseConfig = {
            audio: audioList,
            mutex: true,
            lrcType: this.meta.lrcType || 3,
            storageName: "metingjs",
        };

        if (audioList.length) {
            let finalConfig = _objectSpread({}, baseConfig, this.config);

            for (let key in finalConfig) {
                if (
                    finalConfig[key] === "true" ||
                    finalConfig[key] === "false"
                ) {
                    finalConfig[key] = finalConfig[key] === "true";
                }
            }

            let container = document.createElement("div");
            finalConfig.container = container;

            this.appendChild(container);
            this.aplayer = new APlayer(finalConfig);
        }
    }
}

console.log(
    "\n %c MetingJS v2.0.1 %c https://github.com/metowolf/MetingJS \n",
    "color: #fadfa3; background: #030307; padding:5px 0;",
    "background: #fadfa3; padding:5px 0;"
);

if (window.customElements && !window.customElements.get("meting-js")) {
    window.MetingJSElement = MetingJSElement;
    window.customElements.define("meting-js", MetingJSElement);
}